const input = $('⚡ Entry').item.json;
const cfg   = $('⚙️ Load Config').item.json;

// Validate required fields
const missing = [];
if (!input.article_url)   missing.push('article_url');
if (!input.article_title) missing.push('article_title');

if (missing.length > 0) {
  throw new Error('Blotato Sub-Workflow: missing required fields: ' + missing.join(', '));
}

// Default platforms if not specified
const platforms = input.platforms || ['facebook', 'instagram', 'pinterest'];

return [{ json: {
  article_title:   input.article_title,
  article_url:     input.article_url,
  article_excerpt: input.article_excerpt || '',
  featured_image:  input.featured_image  || '',
  focus_keyword:   input.focus_keyword   || '',
  social_content:  input.social_content  || {},
  platforms,
  cfg_ref: 'loaded'
}}];

const cfg   = $('⚙️ Load Config').item.json;
const input = $('📥 Validate Input').item.json;
const now   = new Date();

function nextOccurrence(daysCsv, hour) {
  const dayMap = {sunday:0,monday:1,tuesday:2,wednesday:3,thursday:4,friday:5,saturday:6};
  const targets = daysCsv.split(',').map(d => dayMap[d.trim().toLowerCase()]).filter(d => d !== undefined);
  for (let i = 1; i <= 8; i++) {
    const d = new Date(now);
    d.setDate(now.getDate() + i);
    d.setHours(parseInt(hour), 0, 0, 0);
    if (targets.includes(d.getDay())) return d.toISOString();
  }
  const fallback = new Date(now);
  fallback.setDate(now.getDate() + 1);
  fallback.setHours(parseInt(hour), 0, 0, 0);
  return fallback.toISOString();
}

function nextWeekday(hour) {
  for (let i = 1; i <= 7; i++) {
    const d = new Date(now);
    d.setDate(now.getDate() + i);
    d.setHours(parseInt(hour), 0, 0, 0);
    if (d.getDay() >= 1 && d.getDay() <= 5) return d.toISOString();
  }
}

const schedule = {
  facebook:  nextOccurrence(cfg.FACEBOOK_POST_DAYS  || 'tuesday,thursday,wednesday', cfg.FACEBOOK_POST_HOUR  || 9),
  instagram: nextWeekday(cfg.INSTAGRAM_POST_HOUR || 11),
  pinterest: nextOccurrence(cfg.PINTEREST_POST_DAYS  || 'saturday,sunday',           cfg.PINTEREST_POST_HOUR || 20),
  tiktok:    nextWeekday(cfg.TIKTOK_POST_HOUR    || 19),
};

return [{ json: { ...input, schedule } }];

const blotato = $input.first().json;
const prev    = $('📅 Calculate Schedule').item.json;
const social  = prev.social_content || {};

// If Blotato remix succeeded, use its output
// Otherwise fall back to Agent 6 social_content from the caller
const hasBlotatoContent = blotato?.facebook?.text || blotato?.posts?.facebook;

const fb_caption  = blotato?.facebook?.text  || blotato?.posts?.facebook?.text  || social?.facebook?.caption  || prev.article_title;
const ig_caption  = blotato?.instagram?.text || blotato?.posts?.instagram?.text || social?.instagram?.caption || prev.article_title;
const pin_title   = blotato?.pinterest?.text || blotato?.posts?.pinterest?.text || social?.pinterest?.title   || prev.article_title;
const pin_desc    = blotato?.pinterest?.description                              || social?.pinterest?.description || '';
const carousel    = blotato?.carousel_url    || blotato?.media?.carousel_url    || '';

return [{ json: {
  ...prev,
  blotato_raw:       blotato,
  used_blotato:      !!hasBlotatoContent,
  captions: {
    facebook:  fb_caption,
    instagram: ig_caption,
    pinterest: pin_title,
    pinterest_desc: pin_desc
  },
  carousel_url: carousel
}}];

const d      = $input.first().json;
const sched  = d.schedule;
const caps   = d.captions;
const platforms = d.platforms || ['facebook','instagram','pinterest'];

const rows = [];

if (platforms.includes('facebook')) {
  rows.push({
    Platform:        'Facebook',
    Content_Type:    'text_link',
    Caption:         caps.facebook + '\n\n' + d.article_url,
    Media_URL:       d.featured_image || '',
    Scheduled_Time:  sched.facebook,
    Status:          'Queued',
    WP_Post_URL:     d.article_url,
    Blotato_Post_ID: '',
    Error_Message:   ''
  });
}

if (platforms.includes('instagram')) {
  rows.push({
    Platform:        'Instagram',
    Content_Type:    d.carousel_url ? 'carousel' : 'image',
    Caption:         caps.instagram,
    Media_URL:       d.carousel_url || d.featured_image || '',
    Scheduled_Time:  sched.instagram,
    Status:          'Queued',
    WP_Post_URL:     d.article_url,
    Blotato_Post_ID: '',
    Error_Message:   ''
  });
}

if (platforms.includes('pinterest')) {
  rows.push({
    Platform:        'Pinterest',
    Content_Type:    'pin',
    Caption:         caps.pinterest + (caps.pinterest_desc ? '\n\n' + caps.pinterest_desc : ''),
    Media_URL:       d.featured_image || '',
    Scheduled_Time:  sched.pinterest,
    Status:          'Queued',
    WP_Post_URL:     d.article_url,
    Blotato_Post_ID: '',
    Error_Message:   ''
  });
}

if (platforms.includes('tiktok')) {
  rows.push({
    Platform:        'TikTok',
    Content_Type:    'video_script',
    Caption:         d.social_content?.tiktok_script || 'Script pending',
    Media_URL:       '',
    Scheduled_Time:  sched.tiktok,
    Status:          'Script_Queued',
    WP_Post_URL:     d.article_url,
    Blotato_Post_ID: '',
    Error_Message:   ''
  });
}

// Pass schedule summary for the Telegram notification
const summary = {
  article_title: d.article_title,
  rows_queued:   rows.length,
  used_blotato:  d.used_blotato,
  schedule:      sched,
  platforms_scheduled: platforms
};

return [{ json: { rows, summary, chat_id: $('⚙️ Load Config').item.json.TELEGRAM_CHAT_ID } }];

const { rows, summary, chat_id } = $input.first().json;

// Tag each row with summary so we can access it after append
return rows.map(r => ({ json: { ...r, _summary: summary, _chat_id: chat_id } }));

const cfg     = $('⚙️ Load Config').item.json;
const items   = $input.all();

// Get summary from first item (all items have the same _summary)
const summary = items[0]?.json?._summary || {};
const tz      = cfg.TIMEZONE || 'Asia/Kuala_Lumpur';

const schedLines = (summary.platforms_scheduled || [])
  .filter(p => ['facebook','instagram','pinterest','tiktok'].includes(p))
  .map(p => {
    const time = summary.schedule?.[p];
    if (!time) return null;
    const label = p.charAt(0).toUpperCase() + p.slice(1);
    return `• ${label} → ${new Date(time).toLocaleString('en-MY', {timeZone: tz, dateStyle:'short', timeStyle:'short'})}`;
  })
  .filter(Boolean)
  .join('\n');

const source = summary.used_blotato ? '✨ Blotato remix' : '📝 Agent 6 fallback';

const msg = `📱 <b>Social Queue Updated</b>\n\n📝 <b>${summary.article_title || 'New Article'}</b>\n📦 Source: ${source}\n\n✅ ${summary.rows_queued} posts queued:\n${schedLines}\n\nQueue Processor will auto-publish at each scheduled time.`;

return [{ json: {
  telegram_message: msg,
  chat_id: cfg.TELEGRAM_CHAT_ID,
  rows_written: items.length,
  article_title: summary.article_title
}}];

// This is what the calling workflow receives back
return [{ json: {
  success:       true,
  rows_written:  $('📱 Build Notify Message').item.json.rows_written,
  article_title: $('📱 Build Notify Message').item.json.article_title,
  message:       'Blotato sub-workflow completed. Posts queued.'
}}];
